// Enhanced Message Preprocessing Node - Fixed for Your Input Structure
const inputData = $input.all();

console.log('=== Message Preprocessing Debug ===');
console.log('Input data length:', inputData.length);
console.log('Input data:', JSON.stringify(inputData, null, 2));

// ✅ Function to replace localhost URLs
function replaceMediaUrl(url) {
    if (url && url.includes('http://localhost:9000')) {
        return url.replace('http://localhost:9000', 'https://bot.creatiqai.com');
    }
    return url;
}

// Phone number normalization function for database
function normalizePhoneNumber(phone) {
    if (!phone) return null;

    let cleanPhone = phone.toString().replace(/\D/g, '');
    if (cleanPhone.startsWith('60')) {
        cleanPhone = cleanPhone.substring(2);
    }
    if (cleanPhone.startsWith('0')) {
        cleanPhone = cleanPhone.substring(1);
    }
    return cleanPhone;
}

// Phone number formatting function for WhatsApp
function formatPhoneForWhatsApp(phone) {
    if (!phone) return null;
    let cleanPhone = phone.toString().replace(/\D/g, '');
    if (!cleanPhone.startsWith('60')) {
        if (cleanPhone.startsWith('0')) {
            cleanPhone = cleanPhone.substring(1);
        }
        cleanPhone = '60' + cleanPhone;
    }
    return cleanPhone;
}

for (const item of inputData) {
    try {
        const body = item.json;
        console.log('Processing item:', JSON.stringify(body, null, 2));

        let userMessage = '';
        let userPhone = '';
        let messageType = 'text';
        let mediaType = 'text';
        let mediaUrl = null;
        let mediaId = null;
        let mediaMimeType = null;
        let isOrderNotification = false;
        let isPaymentSubmission = false;
        let isAdminVerification = false;
        let isDirectWhatsAppSend = false;
        let orderData = null;
        let paymentData = null;
        let adminData = null;
        let directWhatsAppData = null;

        // PRIMARY HANDLER: Chat Input with Session ID (Your main case)
        if (body.chatInput !== undefined && body.sessionId) {
            console.log('Processing chatInput case');

            userMessage = body.chatInput.trim();
            userPhone = body.contact?.phone || body.contact?.name || '60123456789';

            // Handle media messages
            if (body.isMediaMessage === true && body.media) {
                console.log('Media message detected:', body.media);

                mediaType = body.media.type || body.messageType || 'media';
                mediaUrl = replaceMediaUrl(body.media.url);
                mediaMimeType = body.media.metadata?.mime_type || null;
                messageType = body.messageType || mediaType;

                // Set appropriate message based on media type
                if (mediaType === 'audio') {
                    userMessage = 'Audio message - needs transcription';
                } else if (mediaType === 'image') {
                    userMessage = body.chatInput || 'Image search request';
                } else if (mediaType === 'video') {
                    userMessage = body.chatInput || 'Video message received';
                } else if (mediaType === 'document') {
                    userMessage = body.chatInput || 'Document received';
                }

                console.log('Media processing result:', {
                    mediaType,
                    mediaUrl,
                    userMessage
                });
            } else {
                // Regular text message
                messageType = 'text';
                mediaType = 'text';
                console.log('Regular text message');
            }
        }
        // Check for Direct WhatsApp Send (highest priority for other message types)
        else if (body.body && body.body.action === 'direct_whatsapp_send' && 
            (body.body.source === 'admin_approval' || body.body._metadata?.source === 'admin_approval_direct')) {

            isDirectWhatsAppSend = true;
            messageType = 'direct_whatsapp_send';
            mediaType = 'text';

            const messageBody = body.body.text?.body || '';

            directWhatsAppData = {
                to: body.body.to,
                type: body.body.type || 'text',
                text: body.body.text,
                orderId: body.body._metadata?.order_id,
                approvedBy: body.body._metadata?.approved_by,
                timestamp: body.body._metadata?.timestamp,
                bypass_routing: body.body.bypass_routing
            };

            userMessage = `Direct WhatsApp send from admin_approval. Message: ${messageBody.substring(0, 50)}... This is a direct WhatsApp message that should be sent immediately to customer.`;
            userPhone = body.body.to || '60123456789';
        }
        // Check for Admin Verification
        else if (body.body && (body.body._metadata?.source === 'admin_verification' || 
            (body.body.action && (body.body.action === 'verify' || body.body.action === 'reject') && body.body.orderId))) {

            isAdminVerification = true;
            messageType = 'admin_verification';
            mediaType = 'text';

            adminData = {
                action: body.body.action,
                orderId: body.body.orderId,
                adminId: body.body.adminId,
                paymentMethod: body.body.paymentMethod,
                referenceNumber: body.body.referenceNumber,
                notes: body.body.notes,
                timestamp: body.body.timestamp,
                adminName: body.body._metadata?.admin_name || 'Unknown Admin'
            };

            if (body.body.action === 'verify') {
                userMessage = `Admin verify payment for order ${body.body.orderId}. Admin ID: ${body.body.adminId}. Payment method: ${body.body.paymentMethod}. Reference: ${body.body.referenceNumber}. Notes: Payment verified by admin ${adminData.adminName}. This is an admin verification action from admin panel.`;
            } else if (body.body.action === 'reject') {
                userMessage = `Admin reject payment for order ${body.body.orderId}. This is an admin verification action.`;
            }

            userPhone = body.body.customerPhone || '60123456789';
        }
        // Handle WhatsApp messages structure
        else if (body.messages && body.messages[0]) {
            const message = body.messages[0];
            userPhone = message.from;

            if (message.image) {
                mediaType = 'image';
                mediaId = message.image.id;
                mediaMimeType = message.image.mime_type;
                userMessage = message.image.caption || 'Image search request';
                mediaUrl = replaceMediaUrl(message.image.url || `whatsapp://media/${mediaId}`);
            }
            else if (message.audio) {
                mediaType = 'audio';
                mediaId = message.audio.id;
                mediaMimeType = message.audio.mime_type;
                userMessage = 'Audio message - needs transcription';
                mediaUrl = replaceMediaUrl(message.audio.url || `whatsapp://media/${mediaId}`);
            }
            else if (message.video) {
                mediaType = 'video';
                mediaId = message.video.id;
                mediaMimeType = message.video.mime_type;
                userMessage = message.video.caption || 'Video message received';
                mediaUrl = replaceMediaUrl(message.video.url || `whatsapp://media/${mediaId}`);
            }
            else if (message.document) {
                mediaType = 'document';
                mediaId = message.document.id;
                mediaMimeType = message.document.mime_type;
                userMessage = message.document.caption || 'Document received';
                mediaUrl = replaceMediaUrl(message.document.url || `whatsapp://media/${mediaId}`);
            }
            else if (message.text) {
                userMessage = message.text.body;
                messageType = 'text';
                mediaType = 'text';
            }
            else if (message.interactive) {
                userMessage = message.interactive.button_reply?.title || message.interactive.list_reply?.title || '';
                messageType = 'interactive';
                mediaType = 'text';
            }

            if (mediaType === 'text') {
                userMessage = userMessage.trim().toLowerCase();
            }
        }
        // Handle nested body structure
        else if (body.body && body.body.messages && Array.isArray(body.body.messages) && body.body.messages[0]) {
            const message = body.body.messages[0];
            userPhone = message.from || '165230268';

            if (message.image) {
                mediaType = 'image';
                mediaId = message.image.id;
                userMessage = message.image.caption || 'Image search request';
            }
            else if (message.audio) {
                mediaType = 'audio';
                mediaId = message.audio.id;
                userMessage = 'Audio message - needs transcription';
            }
            else if (message.text && message.text.body) {
                mediaType = 'text';
                let messageBody = message.text.body;

                if (messageBody.startsWith('ORDER_NOTIFICATION:')) {
                    isOrderNotification = true;
                    messageType = 'order_notification';
                    try {
                        const jsonStart = messageBody.indexOf('{');
                        if (jsonStart !== -1) {
                            const jsonData = messageBody.substring(jsonStart);
                            orderData = JSON.parse(jsonData);
                            userMessage = `New order notification for order ${orderData.orderId}.`;
                        }
                    } catch (error) {
                        console.error('Error parsing order notification:', error);
                        userMessage = 'Error processing order notification';
                    }
                }
                else if (messageBody.startsWith('PAYMENT_SUBMITTED:')) {
                    isPaymentSubmission = true;
                    messageType = 'payment_submission';
                    try {
                        const jsonStart = messageBody.indexOf('{');
                        if (jsonStart !== -1) {
                            const jsonData = messageBody.substring(jsonStart);
                            paymentData = JSON.parse(jsonData);
                            if (paymentData.customerPhone) {
                                userPhone = paymentData.customerPhone;
                            }
                            userMessage = `Payment submitted for order ${paymentData.orderId}`;
                        }
                    } catch (error) {
                        console.error('Error parsing payment notification:', error);
                        userMessage = 'Error processing payment notification';
                    }
                }
                else {
                    userMessage = messageBody.trim().toLowerCase();
                }
            }
        }
        // Fallback case
        else {
            console.log('Fallback case triggered');
            userPhone = body.contact?.phone || body.contact?.name || body.userPhone || body.phone || body.from || '60123456789';
            userMessage = 'No message body detected';
        }

        // Normalize phone numbers
        const normalizedPhone = normalizePhoneNumber(userPhone);
        const whatsappPhone = formatPhoneForWhatsApp(userPhone);

        console.log('Phone processing:', {
            original: userPhone,
            normalized: normalizedPhone,
            whatsapp: whatsappPhone
        });

        const outputData = {
            originalMessage: body,
            userMessage,
            userPhone: normalizedPhone,
            originalPhone: whatsappPhone,
            messageType,
            mediaType,
            mediaId,
            mediaUrl,
            mediaMimeType,
            extractedOrderId: null,
            extractedSkus: [],
            timestamp: new Date().toISOString(),
            sessionId: body.sessionId || `${normalizedPhone}_${Date.now()}`,
            action: body.action || 'sendMessage',
            isOrderNotification,
            isPaymentSubmission,
            isAdminVerification,
            isDirectWhatsAppSend,
            requiresMediaProcessing: mediaType !== 'text' && mediaType !== 'none'
        };

        // Add additional data objects if they exist
        if (orderData) outputData.orderData = orderData;
        if (paymentData) outputData.paymentData = paymentData;
        if (adminData) outputData.adminData = adminData;
        if (directWhatsAppData) outputData.directWhatsAppData = directWhatsAppData;

        console.log('=== Final Output Data ===');
        console.log(JSON.stringify(outputData, null, 2));

        item.json = outputData;

    } catch (error) {
        console.error('=== ERROR in Message Preprocessing ===');
        console.error('Error:', error.message);
        console.error('Stack:', error.stack);
        console.error('Input item:', JSON.stringify(item.json, null, 2));

        // Return error data to prevent workflow from stopping
        item.json = {
            error: error.message,
            errorStack: error.stack,
            originalMessage: item.json,
            userMessage: 'Error processing message',
            userPhone: '123456789',
            originalPhone: '60123456789',
            messageType: 'error',
            mediaType: 'text',
            timestamp: new Date().toISOString(),
            sessionId: `error_${Date.now()}`,
            requiresMediaProcessing: false
        };
    }
}

console.log('=== Processing Complete ===');
return inputData;

// Unified Media Content Extractor - Handles all media types
const inputData = $input.all();
const preprocessData = $('Message Preprocessing').first().json; // Fixed: removed "1" and changed to .first()

// Function to replace localhost URLs with production URL
function replaceMediaUrl(url) {
    if (url && url.includes('http://localhost:9000')) {
        return url.replace('http://localhost:9000', 'https://bot.creatiqai.com');
    }
    return url;
}

for (const item of inputData) {
    const json = item.json;
    let finalMessage = '';
    let mediaContext = '';

    // Determine the source and extract the appropriate content
    if (preprocessData.mediaType === 'text') {
        // Direct text path - use the original message
        finalMessage = preprocessData.userMessage;
        mediaContext = '';
    } else if (preprocessData.mediaType === 'audio') {
        // Audio transcription - get from current item which comes from OpenAI5/OpenAI13
        // The transcribed text is in the 'text' field
        finalMessage = json.text || json.transcription || json.content || '';
        mediaContext = '';
        console.log('Audio transcription found:', finalMessage);
    } else if (preprocessData.mediaType === 'image') {
        // Image analysis - get from current item which comes from OpenAI3
        const analysisContent = json.content || json.text || '';

        if (analysisContent.includes('I can see')) {
            // Extract the search query part
            const searchMatch = analysisContent.match(/The customer is looking for ([^.]+)/);
            if (searchMatch) {
                finalMessage = searchMatch[1].trim();
            } else {
                finalMessage = analysisContent;
            }
        } else {
            finalMessage = analysisContent;
        }
        mediaContext = '';
        console.log('Image analysis found:', finalMessage);
    } else {
        // Fallback for any other media type
        finalMessage = json.text || json.content || preprocessData.userMessage || '';
    }

    // Ensure we have a message
    if (!finalMessage && preprocessData.userMessage) {
        finalMessage = preprocessData.userMessage;
    }

    // Replace media URLs in the entire preprocessData
    const processedMediaUrl = replaceMediaUrl(preprocessData.mediaUrl);

    // Create consistent output structure for the next nodes
    const output = {
        userMessage: mediaContext + finalMessage,
        originalMessage: preprocessData.originalMessage,
        userPhone: preprocessData.userPhone,
        originalPhone: preprocessData.originalPhone,
        sessionId: preprocessData.sessionId,
        mediaType: preprocessData.mediaType,
        mediaUrl: processedMediaUrl,
        mediaId: preprocessData.mediaId,
        mediaMimeType: preprocessData.mediaMimeType,
        mediaProcessed: true,
        timestamp: new Date().toISOString(),
        messageType: preprocessData.messageType,
        extractedOrderId: preprocessData.extractedOrderId,
        extractedSkus: preprocessData.extractedSkus,
        isOrderNotification: preprocessData.isOrderNotification,
        isPaymentSubmission: preprocessData.isPaymentSubmission,
        isAdminVerification: preprocessData.isAdminVerification,
        isDirectWhatsAppSend: preprocessData.isDirectWhatsAppSend,
        requiresMediaProcessing: preprocessData.requiresMediaProcessing
    };

    // Add specific data if it exists
    if (preprocessData.orderData) output.orderData = preprocessData.orderData;
    if (preprocessData.paymentData) output.paymentData = preprocessData.paymentData;
    if (preprocessData.adminData) output.adminData = preprocessData.adminData;
    if (preprocessData.directWhatsAppData) output.directWhatsAppData = preprocessData.directWhatsAppData;

    // Handle media object if present
    if (json.media && json.media.url) {
        output.media = {
            ...json.media,
            url: replaceMediaUrl(json.media.url)
        };
    }

    console.log('=== Unified Output for Next Node ===');
    console.log('Media Type:', preprocessData.mediaType);
    console.log('Input json:', JSON.stringify(json, null, 2));
    console.log('Final userMessage:', output.userMessage);
    console.log('Media URL:', output.mediaUrl);
    console.log('Media Processed:', output.mediaProcessed);

    item.json = output;
}

return inputData;

// Enhanced Session Manager with existing message type support
const inputData = $input.all();

for (const item of inputData) {
    const data = item.json;

    // Extract phone number - check multiple possible fields
    let customerPhone = data.userPhone || data.customer_phone || data.originalPhone || data.phone;

    // Clean phone number if it exists
    if (customerPhone) {
        // Remove any non-digit characters for session ID
        customerPhone = customerPhone.toString().replace(/\D/g, '');
        // Remove country code 60 if present for consistency
        if (customerPhone.startsWith('60')) {
            customerPhone = customerPhone.substring(2);
        }
        // Remove leading 0 if present
        if (customerPhone.startsWith('0')) {
            customerPhone = customerPhone.substring(1);
        }
    } else {
        // Fallback if no phone found
        customerPhone = 'unknown';
        console.log('Warning: No phone number found in data:', JSON.stringify(data, null, 2));
    }

    // Generate session ID (daily session per phone number)
    const today = new Date().toISOString().split('T')[0];
    const sessionId = `${customerPhone}_${today}`;

    // Enhanced session data with all existing features
    const sessionData = {
        session_id: sessionId,
        customer_phone: customerPhone,
        original_phone: data.originalPhone || data.userPhone,
        message: data.userMessage || data.message,
        timestamp: data.timestamp || new Date().toISOString(),
        message_type: data.messageType,
        media_type: data.mediaType,
        media_url: data.mediaUrl,
        media_processed: data.mediaProcessed,

        // Special message types from your preprocessing
        is_order_notification: data.isOrderNotification,
        is_payment_submission: data.isPaymentSubmission,
        is_admin_verification: data.isAdminVerification,
        is_direct_whatsapp_send: data.isDirectWhatsAppSend,

        // Additional data objects
        order_data: data.orderData || null,
        payment_data: data.paymentData || null,
        admin_data: data.adminData || null,
        direct_whatsapp_data: data.directWhatsAppData || null,

        // Original message for reference
        original_message: data.originalMessage || data.original_message
    };

    console.log('Session Manager Debug:');
    console.log('Input userPhone:', data.userPhone);
    console.log('Extracted customerPhone:', customerPhone);
    console.log('Generated session_id:', sessionId);

    item.json = sessionData;
}

return inputData;

// Clean Parse Memory & Context - Final fix for user_id extraction
const sessionData = $('Session Manager').first().json;
const conversationHistoryArray = $('Get Conversation History').all();
const customerProfileArray = $('Get Customer Profile').all();

console.log('=== Debug Customer Profile Extraction ===');
console.log('Customer Profile Array:', JSON.stringify(customerProfileArray, null, 2));

// Extract customer profile - handle the actual data structure
let customerProfile = null;
if (customerProfileArray?.length > 0) {
    const rawProfileData = customerProfileArray[0].json;
    console.log('Raw Profile Data:', JSON.stringify(rawProfileData, null, 2));

    // The customer profile is directly in the json property
    if (rawProfileData && rawProfileData.user_id) {
        customerProfile = rawProfileData;
        console.log('✅ Customer profile extracted successfully');
        console.log('User ID found:', rawProfileData.user_id);
    } else {
        console.log('❌ No user_id found in profile data');
    }
}

// Extract conversation history
let conversationHistory = [];
let customerContext = {};
let isNewConversation = true;

if (conversationHistoryArray?.length > 0) {
    const reversedConversations = conversationHistoryArray.reverse();

    conversationHistory = reversedConversations.map((item, index) => ({
        text: item.json.conversation_text,
        timestamp: item.json.created_at || item.json.message_timestamp,
        intent: item.json.intent,
        order: index + 1
    }));

    isNewConversation = false;

    const recentIntents = conversationHistory.map(conv => conv.intent).filter(Boolean);
    const userQueries = conversationHistory.map(conv => {
        if (conv.text?.includes('|')) {
            return conv.text.split('|')[0].replace('user:', '').trim();
        }
        return '';
    }).filter(Boolean);

    customerContext = {
        total_conversations: conversationHistoryArray.length,
        recent_intents: [...new Set(recentIntents)],
        last_interaction: conversationHistory[conversationHistory.length - 1]?.timestamp,
        recent_queries: userQueries.slice(-3).join(', ')
    };
}

// Build result - CRITICAL: Set customer_user_id correctly
const result = {
    session_id: sessionData.session_id,
    customer_phone: sessionData.customer_phone,
    message: sessionData.message,
    timestamp: sessionData.timestamp,

    // Customer profile information
    customer_profile: customerProfile,
    customer_name: customerProfile?.full_name || 'Customer',
    customer_type: customerProfile?.customer_type || 'regular',
    customer_user_id: customerProfile?.user_id || null, // This MUST match the field name in your data
    has_user_profile: !!customerProfile,

    conversation_history: conversationHistory,
    customer_context: customerContext,
    is_new_conversation: isNewConversation,

    ...(sessionData.media_type !== 'text' && {
        media_type: sessionData.media_type,
        media_url: sessionData.media_url
    }),

    ...(sessionData.is_order_notification && { is_order_notification: true }),
    ...(sessionData.is_payment_submission && { is_payment_submission: true }),
    ...(sessionData.is_admin_verification && { is_admin_verification: true }),
    ...(sessionData.is_direct_whatsapp_send && { is_direct_whatsapp_send: true })
};

console.log('=== Final Result Debug ===');
console.log('customer_user_id:', result.customer_user_id);
console.log('customer_profile.user_id:', result.customer_profile?.user_id);
console.log('Full result:', JSON.stringify(result, null, 2));

return [{ json: result }];

