// Response Processor for Single Table with Formatted Conversation
const agentResponse = $('Fine Tuning Agent').first().json;
const sessionData = $('Parse Memory & Context').first().json;

// Extract response content
let responseContent = '';
let toolsUsed = [];
let confidence = 0.95;

if (typeof agentResponse === 'string') {
    responseContent = agentResponse;
} else if (agentResponse.output) {
    responseContent = agentResponse.output;
} else if (agentResponse.content) {
    responseContent = agentResponse.content;
} else if (agentResponse.text) {
    responseContent = agentResponse.text;
} else {
    responseContent = JSON.stringify(agentResponse);
}

// Extract tool usage from the ORIGINAL Autolab Master AI Agent response
const originalAgentResponse = $('Autolab Master AI Agent').first().json;
if (originalAgentResponse.tool_calls && Array.isArray(originalAgentResponse.tool_calls)) {
    toolsUsed = originalAgentResponse.tool_calls.map(call => call.function?.name || call.name);
}

// Determine intent
let detectedIntent = 'general_chat';
if (responseContent.toLowerCase().includes('product') || responseContent.toLowerCase().includes('accessories')) {
    detectedIntent = 'product_search';
} else if (responseContent.toLowerCase().includes('order') || responseContent.toLowerCase().includes('tracking')) {
    detectedIntent = 'order_status';
} else if (responseContent.toLowerCase().includes('policy') || responseContent.toLowerCase().includes('warranty')) {
    detectedIntent = 'knowledge_base';
}

// Clean the messages for formatting (remove quotes and escape characters)
const cleanUserMessage = sessionData.message.replace(/"/g, "'").replace(/\n/g, " ").trim();
const cleanBotMessage = responseContent.replace(/"/g, "'").replace(/\n/g, " ").trim();

// Format conversation as single string
const formattedConversation = `user: ${cleanUserMessage} | assistant: ${cleanBotMessage}`;

// Get Malaysia timezone timestamp
const malaysiaTime = new Date().toLocaleString("en-US", {timeZone: "Asia/Kuala_Lumpur"});
const malaysiaTimestamp = new Date(malaysiaTime).toISOString();

// Prepare data for single table insert
const conversationData = {
    session_id: sessionData.session_id,
    customer_phone: sessionData.customer_phone,
    customer_profile_id: sessionData.customer_profile?.id || null,
    conversation_text: formattedConversation,
    intent: detectedIntent,
    tools_used: toolsUsed.length > 0 ? toolsUsed : null,
    confidence: confidence,
    media_type: sessionData.media_type || 'text',
    media_url: sessionData.media_url || null,
    message_timestamp: malaysiaTimestamp
};

console.log('Formatted conversation:', formattedConversation);
console.log('Malaysia timestamp:', malaysiaTimestamp);

return [{
    json: {
        conversationData: conversationData,
        responseContent: responseContent,
        sessionId: sessionData.session_id,
        customerPhone: sessionData.customer_phone
    }
}];

// Simple Response Message Extractor
const responseData = $('Response Processor').first().json;

// Extract just the response content
const message = responseData.responseContent;

// Return simple format for Final Response node
return [{
    json: {
        output: message
    }
}];

